function scan(node) {
  for (const el of node.querySelectorAll('*')) {
    const cs = getComputedStyle(el);
    if ((cs.opacity < 0.05 || cs.display === 'none') && el.textContent.trim()) flag(el);
    if (el.shadowRoot) scan(el.shadowRoot); // descend into Lit's shadow root
  }
}
scan(document.body);
